$kbCorrecifs = @("KB5066586", "KB5066782", "KB5066791", "KB5066793", "KB5066835", "KB5066780", "KB5066837", "KB5066836", "KB5066875", "KB5066873")
$Session  = New-Object -ComObject Microsoft.Update.Session
$Searcher = $Session.CreateUpdateSearcher()
$Updates  = $Searcher.Search("IsInstalled=1").Updates
$installes = $Updates | ForEach-Object { $_.KBArticleIDs } | ForEach-Object { "KB$_" }
$presents = $kbCorrecifs | Where-Object { $installes -contains $_ }
if ($presents.Count -gt 0) {
    Write-Host "✅ PROTÉGÉ   - CVE-2025-47827 : correctif présent ($($presents -join ', '))" -ForegroundColor Green
} else {
    Write-Host "⚠️  VULNÉRABLE - CVE-2025-47827 : aucun correctif installé (ou CVE non applicable à cet OS)" -ForegroundColor Red
}
